/**
 * DELIVERABLES_COMPLETENESS Semantic Gate
 * Part of SD-LEO-FEAT-SEMANTIC-VALIDATION-GATES-002 (Gate 2)
 *
 * Verifies that all promised deliverables are actually completed.
 * Checks sd_scope_deliverables completion_status and detects auto-generated artifacts.
 *
 * Phase: EXEC-TO-PLAN
 */

import {
  getGateApplicability,
  computeConfidence,
  isAutoGenerated,
  buildSemanticResult,
  buildSkipResult
} from '../../../validation/semantic-gate-utils.js';

const GATE_NAME = 'DELIVERABLES_COMPLETENESS';

export function createDeliverablesCompletenessGate(supabase) {
  return {
    name: GATE_NAME,
    validator: async (ctx) => {
      console.log('\n📦 SEMANTIC GATE: Deliverables Completeness');
      console.log('-'.repeat(50));

      const sdType = ctx.sd?.sd_type || ctx.sdType || 'feature';
      const sdId = ctx.sd?.id || ctx.sdId;

      // Check applicability
      const { applicable, level } = getGateApplicability(GATE_NAME, sdType);
      if (!applicable) {
        console.log(`   ℹ️  Skipped for SD type: ${sdType}`);
        return buildSkipResult(GATE_NAME, sdType);
      }

      if (!supabase || !sdId) {
        console.log('   ⚠️  Missing supabase client or SD ID');
        return buildSemanticResult({
          passed: true, score: 50, confidence: 0.3,
          warnings: ['Cannot validate deliverables — missing database context']
        });
      }

      try {
        // Query deliverables for this SD
        const { data: deliverables, error } = await supabase
          .from('sd_scope_deliverables')
          .select('id, deliverable_name, completion_status, metadata, created_by')
          .eq('sd_id', sdId);

        if (error) {
          console.log(`   ⚠️  Database error: ${error.message}`);
          return buildSemanticResult({
            passed: true, score: 50, confidence: 0.3,
            warnings: [`Database error: ${error.message}`]
          });
        }

        if (!deliverables || deliverables.length === 0) {
          console.log('   ⚠️  No deliverables found in sd_scope_deliverables — trying JIT extraction');

          // Fallback 1: JIT extract from PRD
          let jitExtracted = false;
          try {
            // Resolve SD text key for PRD lookup (sdId may be text key or UUID)
            const sdTextKey = ctx.sd?.id || sdId;

            const { data: prd } = await supabase
              .from('product_requirements_v2')
              .select('*')
              .eq('directive_id', sdTextKey)
              .single();

            if (prd) {
              console.log('   📄 Found PRD — extracting deliverables via JIT');
              const { extractAndPopulateDeliverables } = await import('../../../extract-deliverables-from-prd.js');
              const result = await extractAndPopulateDeliverables(sdId, prd, supabase, { silent: true, skipIfExists: false });

              if (result.success && result.count > 0) {
                console.log(`   ✅ JIT extracted ${result.count} deliverables from PRD`);
                jitExtracted = true;

                // Re-query now that deliverables are populated
                const { data: newDeliverables } = await supabase
                  .from('sd_scope_deliverables')
                  .select('id, deliverable_name, completion_status, metadata, created_by')
                  .eq('sd_id', sdId);

                if (newDeliverables && newDeliverables.length > 0) {
                  // Score the newly extracted deliverables using existing logic below
                  let total = newDeliverables.length;
                  let completed = 0;
                  let autoGenCount = 0;
                  const missing = [];

                  for (const d of newDeliverables) {
                    if (isAutoGenerated(d)) { autoGenCount++; missing.push(`${d.deliverable_name} (auto-generated)`); continue; }
                    if (d.completion_status === 'completed' || d.completion_status === 'done') { completed++; }
                    else { missing.push(`${d.deliverable_name} (status: ${d.completion_status || 'pending'})`); }
                  }

                  const effectiveTotal = total - autoGenCount;
                  const score = effectiveTotal > 0 ? Math.round((completed / effectiveTotal) * 100) : 0;
                  const confidence = computeConfidence({ dataPoints: total, expectedPoints: Math.max(total, 3) });
                  const passed = level === 'OPT' ? true : score >= 85;

                  console.log(`   📊 JIT Deliverables: ${completed}/${effectiveTotal} completed`);
                  console.log(`   ${passed ? '✅' : '❌'} Score: ${score}/100 | Confidence: ${confidence}`);

                  return buildSemanticResult({
                    passed, score, confidence,
                    issues: !passed ? [`${missing.length} deliverable(s) incomplete (JIT extracted)`] : [],
                    warnings: ['Deliverables populated via JIT PRD extraction'],
                    details: { total, completed, autoGenerated: autoGenCount, missing, completionRate: score, source: 'jit_prd_extraction' },
                    remediation: !passed ? `Complete remaining deliverables: ${missing.join(', ')}` : undefined
                  });
                }
              }
            }
          } catch (jitErr) {
            console.log(`   ⚠️  JIT extraction failed: ${jitErr.message}`);
          }

          // Fallback 2: Check success_criteria from the SD itself
          if (!jitExtracted) {
            try {
              const sdTextKey = ctx.sd?.id || sdId;
              const { data: sd } = await supabase
                .from('strategic_directives_v2')
                .select('success_criteria, success_metrics')
                .eq('id', sdTextKey)
                .single();

              const criteria = sd?.success_criteria || sd?.success_metrics || [];
              if (Array.isArray(criteria) && criteria.length > 0) {
                const count = criteria.length;
                const score = Math.min(40 + (count * 5), 60);
                console.log(`   📋 Using success_criteria fallback (${count} criteria) — score: ${score}`);

                return buildSemanticResult({
                  passed: level === 'OPT' ? true : score >= 85,
                  score,
                  confidence: 0.5,
                  warnings: [`No deliverables tracked — scored from ${count} success criteria (${score}%)`],
                  details: { criteriaCount: count, source: 'success_criteria_fallback' }
                });
              }
            } catch (scErr) {
              console.log(`   ⚠️  Success criteria fallback failed: ${scErr.message}`);
            }
          }

          // Final fallback: no data available
          console.log('   ❌ No deliverables, PRD, or success criteria available');
          return buildSemanticResult({
            passed: level === 'OPT', score: level === 'OPT' ? 50 : 0,
            confidence: 0.8,
            issues: level === 'REQ' ? ['No deliverables found — cannot verify completeness'] : [],
            warnings: level === 'OPT' ? ['No deliverables found — optional for this SD type'] : [],
            remediation: 'Ensure deliverables are tracked in sd_scope_deliverables table'
          });
        }

        const total = deliverables.length;
        let completed = 0;
        let autoGenCount = 0;
        const missing = [];

        for (const d of deliverables) {
          if (isAutoGenerated(d)) {
            autoGenCount++;
            missing.push(`${d.deliverable_name} (auto-generated — scores 0)`);
            continue;
          }

          if (d.completion_status === 'completed' || d.completion_status === 'done') {
            completed++;
          } else {
            missing.push(`${d.deliverable_name} (status: ${d.completion_status || 'unknown'})`);
          }
        }

        const effectiveTotal = total - autoGenCount;
        const score = effectiveTotal > 0 ? Math.round((completed / effectiveTotal) * 100) : 0;
        const confidence = computeConfidence({ dataPoints: total, expectedPoints: Math.max(total, 3) });
        const passed = level === 'OPT' ? true : score >= 85;

        console.log(`   📊 Deliverables: ${completed}/${effectiveTotal} completed (${total} total, ${autoGenCount} auto-generated)`);
        console.log(`   ${passed ? '✅' : '❌'} Score: ${score}/100 | Confidence: ${confidence}`);

        if (missing.length > 0) {
          console.log('   Missing:');
          missing.forEach(m => console.log(`      - ${m}`));
        }

        return buildSemanticResult({
          passed,
          score,
          confidence,
          issues: !passed ? [`${missing.length} deliverable(s) incomplete`] : [],
          warnings: level === 'OPT' && score < 85 ? [`Low deliverable completion (${score}%) — advisory`] : [],
          details: {
            total, completed, autoGenerated: autoGenCount,
            missing, completionRate: score
          },
          remediation: !passed ? `Complete remaining deliverables: ${missing.join(', ')}` : undefined
        });
      } catch (err) {
        console.log(`   ⚠️  Error: ${err.message}`);
        return buildSemanticResult({
          passed: true, score: 50, confidence: 0.3,
          warnings: [`Deliverables check error: ${err.message}`]
        });
      }
    },
    required: true,
    weight: 1.0
  };
}
